sql:
SELECT chemical_name, trade_secret
FROM chemicals
ORDER BY chemical_name ASC;

external_knowledge:
- 'Non-trade secret' means the chemical information is publicly available or not classified as a trade secret; 
- 'Last updated before 2020' refers to the year of the last update to the chemical record being less than 2020; 
- 'Active formulation' refers to the status of the formulation being 'Active'.

sql:
SELECT c.chemical_name, c.synonyms, c.cas_no, u.user_name
FROM chemicals c
JOIN users u ON c.last_updated = u.last_login;

SELECT chemical_name, synonyms, molecular_formula
FROM chemicals
WHERE trade_secret = 1;

SELECT chemical_name
FROM chemicals
ORDER BY chemical_name ASC;

SELECT chemical_id, chemical_name, trade_secret
FROM chemicals
WHERE chemical_name LIKE 'Acet%';

SELECT chemicals.chemical_name, hazard_classifications.hazard_class
FROM chemicals
JOIN hazard_classifications ON chemicals.chemical_id = hazard_classifications.chemical_id;

SELECT chemicals.chemical_name, ems.emergency_contact
FROM chemicals
JOIN ems ON chemicals.chemical_id = ems.chemical_id;
